const clients = $("Fetch Clients").all().map(function(i){ return i.json; }).filter(function(j){ return j && Object.keys(j).length>0; });
const logRows = $("Fetch Log").all().map(function(i){ return i.json||{}; });
const threshold = 200000;
const today = new Date().toISOString().slice(0,10);
function num(v){ if(v==null) return 0; var n=parseFloat(String(v).replace(/[^0-9.]/g,"")); return isFinite(n)?n:0; }
function norm(p){ var d=String(p||"").replace(/[^0-9]/g,""); if(d.length>10) d=d.slice(-10); return d; }
const lastMap={};
logRows.forEach(function(l){ if(l && l.family){ var dt=l.lastDispatchedOn||""; if(!lastMap[l.family] || dt>lastMap[l.family]) lastMap[l.family]=dt; } });
const fam={};
clients.forEach(function(r){
  var key=(r.groupName && String(r.groupName).trim()) || ("SOLO:"+(r.name||r.phoneLast10||r._id));
  if(!fam[key]) fam[key]={family:key, members:{}, premium:0, phones:[]};
  if(r.name) fam[key].members[String(r.name).trim()]=true;
  fam[key].premium+=num(r.premium);
  var ph=norm(r.phoneLast10||r.phone);
  if(ph.length===10 && fam[key].phones.indexOf(ph)<0) fam[key].phones.push(ph);
});
var families=Object.keys(fam).map(function(k){ var f=fam[k]; var famName=f.family.indexOf("SOLO:")===0?f.family.slice(5):f.family; return {family:famName, members:Object.keys(f.members).length, premium:Math.round(f.premium), phone:f.phones[0]||"", last:lastMap[famName]||""}; });
var eligible=families.filter(function(f){ return f.premium>threshold && f.phone; });
eligible.sort(function(a,b){ if(a.last!==b.last) return a.last<b.last?-1:1; return b.premium-a.premium; });
var pick=eligible.slice(0,10);
return pick.map(function(f){
  var nm=f.family;
  var msg="🎁 Namaste "+nm+" parivaar! Aapna vishwaas badal CGPE taraf thi ek nanakdi bhet swikaarso. Aapni sathe ni bhagidaari amaara maate garv ni vaat chhe. 🙏 — C. G. Patel Enterprise";
  return { json: { family:nm, phone:"91"+f.phone, premium:f.premium, members:f.members, message:msg, lastDispatchedOn:today } };
});

const list=$("Pick Families").all().map(function(i){ return i.json; });
const admins=$("Fetch Admins").all().map(function(i){ return i.json||{}; });
function norm(p){ var d=String(p||"").replace(/[^0-9]/g,""); if(d.length>10) d=d.slice(-10); return d; }
var ap=admins.length?norm(admins[0].phoneLast10||admins[0].phone):"9601775061";
if(ap.length===10) ap="91"+ap;
if(!list.length){ return [{ json:{ phone:ap, text:"🎁 Aa cycle maate koi navi hamper-eligible family nathi.", purpose:"hamper_dispatch" } }]; }
var lines=list.map(function(p,i){ return (i+1)+". "+p.family+" ("+p.phone+") — Rs "+p.premium+"\n   Msg: "+p.message; });
var text="🎁 Gift hamper dispatch — "+list.length+" families (premium > 2 lakh):\n\n"+lines.join("\n\n")+"\n\nHamper mokli, saathe aa personalised message aapo.";
return [{ json:{ phone:ap, text:text, purpose:"hamper_dispatch" } }];

// Expand one composed admin message into one item per opted-in admin.
// Kept separate from 'Compose Admin' so its other branches still see a single item.
const msg = $('Compose Admin').first().json || {};
let admins = [];
try { admins = $('Fetch Admins').all().map(function (i) { return i.json || {}; }); } catch (e) { admins = []; }
function norm(p) { return String(p || '').replace(/[^0-9]/g, '').slice(-10); }

const seen = {};
const out = [];
for (const a of admins) {
  if (!a || a.isActive === false || a.active === false) continue;
  if (a.notifyEnquiries !== true) continue;   // admins opt in; the rest keep their rights
  const p = norm(a.phoneLast10 || a.phone || a.phoneNumber);
  if (p.length !== 10 || seen[p]) continue;
  seen[p] = true;
  out.push({ json: Object.assign({}, msg, { phone: '91' + p, adminName: a.name || '' }) });
}
if (!out.length) out.push({ json: Object.assign({}, msg, { phone: '919601775061', adminName: 'CGPE Admin' }) });
return out;
